import React, { useState, useRef } from 'react';

function UploadForm({ onAnalyze, onFileUpload }) {
  const [file, setFile] = useState(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [notification, setNotification] = useState(null);
  const fileInputRef = useRef(null);

  const supportedTypes = ['video/mp4', 'video/avi', 'video/mov', 'video/wmv', 'audio/wav', 'audio/mp3', 'audio/m4a', 'audio/flac'];
  const maxSize = 100 * 1024 * 1024; // 100MB

  const validateFile = (file) => {
    if (!supportedTypes.includes(file.type)) {
      return 'Unsupported file type. Please upload MP4, AVI, MOV, WMV, WAV, MP3, M4A, or FLAC files.';
    }
    if (file.size > maxSize) {
      return 'File size exceeds 100MB limit.';
    }
    return null;
  };

  const handleFileSelect = (selectedFile) => {
    const error = validateFile(selectedFile);
    if (error) {
      setNotification({ type: 'error', message: error });
      return;
    }
    setFile(selectedFile);
    onFileUpload(selectedFile);
    setNotification({ type: 'success', message: 'File uploaded successfully!' });
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragOver(false);
    const droppedFile = e.dataTransfer.files[0];
    if (droppedFile) {
      handleFileSelect(droppedFile);
    }
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = () => {
    setIsDragOver(false);
  };

  const handleFileInputChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      handleFileSelect(selectedFile);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current.click();
  };

  const simulateUpload = () => {
    setIsUploading(true);
    setUploadProgress(0);
    const interval = setInterval(() => {
      setUploadProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsUploading(false);
          setNotification({ type: 'success', message: 'Upload completed!' });
          return 100;
        }
        return prev + 10;
      });
    }, 200);
  };

  const handleAnalyze = () => {
    if (!file) {
      setNotification({ type: 'error', message: 'Please upload a file first.' });
      return;
    }
    simulateUpload();
    // Simulate analysis
    setTimeout(() => {
      const dummyResult = {
        audio: file.type.startsWith('audio/') ? 'real' : 'N/A',
        video: file.type.startsWith('video/') ? 'fake' : 'N/A',
        confidence: Math.random() * 0.5 + 0.5,
      };
      onAnalyze(dummyResult);
    }, 2000);
  };

  return (
    <div className="card">
      <h3>Upload File</h3>
      <div
        className={`upload-area ${isDragOver ? 'dragover' : ''}`}
        onDrop={handleDrop}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onClick={handleUploadClick}
      >
        <p>Drag and drop a file here, or click to select</p>
        <p>Supported formats: MP4, AVI, MOV, WMV, WAV, MP3, M4A, FLAC</p>
        <p>Max size: 100MB</p>
        <input
          ref={fileInputRef}
          type="file"
          accept="video/*,audio/*"
          onChange={handleFileInputChange}
          style={{ display: 'none' }}
        />
      </div>
      {isUploading && (
        <div className="progress-bar">
          <div className="progress-fill" style={{ width: `${uploadProgress}%` }}></div>
        </div>
      )}
      {notification && (
        <div className={`notification ${notification.type}`}>
          {notification.message}
        </div>
      )}
      <button className="btn" onClick={handleAnalyze} disabled={isUploading}>
        {isUploading ? 'Analyzing...' : 'Analyze'}
      </button>
    </div>
  );
}

export default UploadForm;
